class Solution(object):
    def longestMonotonicSubarray(self, nums):
        n = len(nums)
        if n == 1:
            return 1
        inc = dec = max_len = 1
        for i in range(1, n):
            if nums[i] > nums[i - 1]:
                inc += 1
                dec = 1
            elif nums[i] < nums[i - 1]:
                dec += 1
                inc = 1
            else:
                inc = dec = 1
            max_len = max(max_len, inc, dec)
        return max_len
